def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    import pymoo
    from pymoo.indicators.hv import HV

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    n, m = points.shape

    def compute_hv(subset_indices):
        if len(subset_indices) == 0:
            return 0.0
        selected = points[list(subset_indices)]
        ind = HV(ref_point=reference_point)
        return ind(selected)

    def restricted_candidate_list(current_set, alpha=0.3):
        candidates = list(set(range(n)) - current_set)
        if not candidates:
            return []

        contributions = []
        for cand in candidates:
            temp_set = current_set | {cand}
            hv_with = compute_hv(temp_set)
            hv_without = compute_hv(current_set)
            contributions.append(hv_with - hv_without)

        contributions = np.array(contributions)
        max_contrib = np.max(contributions)
        min_contrib = np.min(contributions)

        threshold = min_contrib + alpha * (max_contrib - min_contrib)
        rcl = [candidates[i] for i in range(len(candidates)) if contributions[i] >= threshold]

        return rcl if rcl else candidates

    def grasp_construction(alpha=0.3):
        current_set = set()
        while len(current_set) < k:
            rcl = restricted_candidate_list(current_set, alpha)
            if not rcl:
                break
            chosen = random.choice(rcl)
            current_set.add(chosen)
        return current_set

    def local_search(solution_set):
        current_set = set(solution_set)
        improved = True

        while improved:
            improved = False
            current_hv = compute_hv(current_set)

            for s in list(current_set):
                for r in set(range(n)) - current_set:
                    new_set = (current_set - {s}) | {r}
                    new_hv = compute_hv(new_set)

                    if new_hv > current_hv:
                        current_set = new_set
                        current_hv = new_hv
                        improved = True
                        break
                if improved:
                    break

        return current_set

    def path_relinking(set1, set2):
        symmetric_diff = list(set1 ^ set2)
        random.shuffle(symmetric_diff)

        current_set = set(set1)
        best_set = set(set1)
        best_hv = compute_hv(set1)

        for elem in symmetric_diff:
            if elem in current_set:
                current_set.remove(elem)
            else:
                current_set.add(elem)

            if len(current_set) == k:
                current_hv = compute_hv(current_set)
                if current_hv > best_hv:
                    best_set = set(current_set)
                    best_hv = current_hv

        return best_set

    best_solution = None
    best_hv = -np.inf

    for iteration in range(10):
        alpha = random.uniform(0.1, 0.5)
        constructed = grasp_construction(alpha)

        if len(constructed) < k:
            remaining = list(set(range(n)) - constructed)
            needed = k - len(constructed)
            constructed.update(random.sample(remaining, min(needed, len(remaining))))

        improved = local_search(constructed)

        if best_solution is None:
            best_solution = improved
            best_hv = compute_hv(improved)
        else:
            relinked = path_relinking(best_solution, improved)
            relinked_hv = compute_hv(relinked)

            if relinked_hv > best_hv:
                best_solution = relinked
                best_hv = relinked_hv

    return points[list(best_solution)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Fast hypervolume calculation using WFG algorithm
    def fast_hv(subset_indices):
        if len(subset_indices) == 0:
            return 0.0
        data = points[subset_indices]
        hv = pg.hypervolume(data)
        return hv.compute(reference_point)

    # Fast incremental hypervolume contribution
    def fast_contrib(candidate_idx, current_indices):
        if len(current_indices) == 0:
            return fast_hv([candidate_idx])

        # Calculate contribution using inclusion-exclusion
        current_hv = fast_hv(current_indices)
        combined = list(current_indices) + [candidate_idx]
        combined_hv = fast_hv(combined)
        return combined_hv - current_hv

    # Lookahead evaluation for 2-step greedy
    def lookahead_contrib(candidate_idx, current_indices, depth=2):
        if depth == 0:
            return fast_contrib(candidate_idx, current_indices)

        # Get remaining candidates
        remaining = [i for i in range(n) if i not in current_indices and i != candidate_idx]
        if not remaining:
            return fast_contrib(candidate_idx, current_indices)

        # Try adding candidate first, then find best companion
        new_indices = list(current_indices) + [candidate_idx]
        best_gain = -np.inf

        # Sample subset of remaining points for efficiency
        sample_size = min(10, len(remaining))
        sampled = np.random.choice(remaining, size=sample_size, replace=False)

        for comp_idx in sampled:
            gain = fast_contrib(comp_idx, new_indices)
            if gain > best_gain:
                best_gain = gain

        return fast_contrib(candidate_idx, current_indices) + 0.3 * best_gain

    # Diversity penalty based on angle diversity
    def diversity_penalty(candidate_idx, current_indices):
        if len(current_indices) == 0:
            return 0.0

        candidate_vec = points[candidate_idx] - reference_point
        candidate_norm = np.linalg.norm(candidate_vec)
        if candidate_norm == 0:
            return 0.0

        min_cosine = 1.0
        for idx in current_indices:
            existing_vec = points[idx] - reference_point
            existing_norm = np.linalg.norm(existing_vec)
            if existing_norm == 0:
                continue

            cosine = np.dot(candidate_vec, existing_vec) / (candidate_norm * existing_norm)
            min_cosine = min(min_cosine, cosine)

        # Penalize points too similar to existing ones
        return max(0, min_cosine - 0.5) * 0.1

    selected_indices = []

    # Phase 1: Greedy selection with lookahead
    for step in range(k):
        best_score = -np.inf
        best_idx = None

        # Evaluate all candidates
        for idx in range(n):
            if idx in selected_indices:
                continue

            # Base contribution
            base_contrib = fast_contrib(idx, selected_indices)

            # Lookahead contribution (only in early stages)
            if step < k // 2:
                lookahead = lookahead_contrib(idx, selected_indices, depth=1)
                contrib = 0.7 * base_contrib + 0.3 * lookahead
            else:
                contrib = base_contrib

            # Diversity adjustment
            div_penalty = diversity_penalty(idx, selected_indices)
            score = contrib * (1.0 - div_penalty)

            if score > best_score:
                best_score = score
                best_idx = idx

        if best_idx is not None:
            selected_indices.append(best_idx)
        else:
            # Fallback: select random unselected point
            remaining = [i for i in range(n) if i not in selected_indices]
            if remaining:
                selected_indices.append(np.random.choice(remaining))
            else:
                break

    # Phase 2: Local improvement by swapping
    for _ in range(min(5, k)):
        current_hv = fast_hv(selected_indices)
        improved = False

        # Try swapping each selected point with unselected ones
        for i, sel_idx in enumerate(selected_indices):
            for unsel_idx in range(n):
                if unsel_idx in selected_indices:
                    continue

                # Create trial set
                trial_indices = selected_indices.copy()
                trial_indices[i] = unsel_idx

                trial_hv = fast_hv(trial_indices)
                if trial_hv > current_hv:
                    selected_indices = trial_indices
                    current_hv = trial_hv
                    improved = True
                    break

            if improved:
                break

        if not improved:
            break

    return points[selected_indices]
